fix:
Object returnValueFor(Class<?> type) {
    if (Primitives.isPrimitiveOrWrapper(type)) {
        return Primitives.defaultValueForPrimitiveOrWrapper(type);
    } else if (Iterable.class.isAssignableFrom(type)) {
        try{
            Constructor constructor = type.getConstructor();
            return (Object)constructor.newInstance();
        }catch(Exception e){
          throw new RuntimeException("Cannot instantiate iterable");
       } 
    } else if (type == Collection.class || Collection.class.isAssignableFrom(type)) {
        return new ArrayList<>();
    } else if (type == Set.class || Set.class.isAssignableFrom(type)) {
        return new HashSet<>();
    } else if (type == List.class || List.class.isAssignableFrom(type)) {
        return new ArrayList<>();
    } else if (type == Map.class || Map.class.isAssignableFrom(type)) {
        return new HashMap<>();
    }  
    return null;
}

